#include <iostream>
#include <string>
#include <fstream>
using namespace std;

// Define a Product struct with: name, price, quantity, category

int searchByName(Product products[], int count, string target) {
    for (int i = 0; i < count; i++) {
        if (products[i].name == target)
            return i;
    }
    return -1;
}

void sortByPrice(Product products[], int count) {
    for (int i = 0; i < count - 1; i++) {
        for (int j = 0; j < count - i - 1; j++) {
            if (products[j].price > products[j + 1].price) {
                Product temp = products[j];
                products[j] = products[j + 1];
                products[j + 1] = temp;
            }
        }
    }
}

int main() {
    int capacity;
    cout << "Enter inventory capacity: ";
    cin >> capacity;

    Product *products = new Product[capacity];
    int productCount = 0;
    int choice;

    do {
        cout << "\n===== Inventory Management System =====" << endl;
        cout << "1. Add Product" << endl;
        cout << "2. View Products" << endl;
        cout << "3. Search Product" << endl;
        cout << "4. Sort Products" << endl;
        cout << "5. Save to File" << endl;
        cout << "6. Exit" << endl;
        cout << "Enter your choice: ";
        cin >> choice;

        switch (choice) {
            case 1: {
                if (productCount >= capacity) {
                    cout << "Inventory full!" << endl;
                    break;
                }
                cin.ignore();
                cout << "Enter product name: ";
                getline(cin, products[productCount].name);
                cout << "Enter category: ";
                getline(cin, products[productCount].category);
                cout << "Enter price: ";
                cin >> products[productCount].price;
                cout << "Enter quantity: ";
                cin >> products[productCount].quantity;
                if (products[productCount].price > 0 && products[productCount].quantity >= 0) {
                    productCount++;
                    cout << "Product added!" << endl;
                } else {
                    cout << "Invalid input." << endl;
                }
                break;
            }
            case 2: {
                for (int i = 0; i < productCount; i++) {
                    // Display using dot operator: products[i].name, etc.
                }
                break;
            }
            case 3: {
                cin.ignore();
                string target;
                cout << "Enter product name to search: ";
                getline(cin, target);
                int idx = searchByName(products, productCount, target);
                if (idx != -1)
                    cout << "Found: " << products[idx].name
                         << " [" << products[idx].category << "] $"
                         << products[idx].price << " x " << products[idx].quantity << endl;
                else
                    cout << "Product not found." << endl;
                break;
            }
            case 4: {
                sortByPrice(products, productCount);
                cout << "Products sorted by price." << endl;
                break;
            }
            case 5: {
                ofstream outFile("inventory.txt");
                for (int i = 0; i < productCount; i++) {
                    outFile << products[i].name << "," << products[i].category << ","
                            << products[i].price << "," << products[i].quantity << endl;
                }
                outFile.close();
                cout << "Saved to inventory.txt" << endl;
                break;
            }
            case 6:
                cout << "Goodbye!" << endl;
                break;
            default:
                cout << "Invalid choice." << endl;
        }
    } while (choice != 6);

    delete[] products;
    return 0;
}
